#!/usr/bin/env bun
/**
 * MMS Development Server Orchestrator
 *
 * Starts all services needed for local development:
 * - API Server (Hono) on PORT (default: 3000)
 * - Frontend (Vite) with proxy to API
 * - Workers (optional, set WORKERS env var)
 *
 * Usage:
 *   bun run scripts/dev.ts           # Start API + Frontend
 *   WORKERS=all bun run scripts/dev.ts  # Include all workers
 *
 * Environment Variables:
 *   PORT          - API server port (default: 3000)
 *   VITE_PORT     - Frontend port (default: 5173)
 *   WORKERS       - Comma-separated worker list or 'all' (default: none)
 *   VITE_API_URL  - Auto-set based on PORT
 */

import { spawn, type Subprocess } from 'bun';
import { resolve } from 'path';

const ROOT = resolve(import.meta.dir, '..');
const API_PORT = process.env.PORT || '3000';
const VITE_PORT = process.env.VITE_PORT || '5173';
const WORKERS = process.env.WORKERS || '';

const processes: Subprocess[] = [];
let shuttingDown = false;

function log(service: string, message: string, color: string = '\x1b[0m') {
  const timestamp = new Date().toISOString().split('T')[1].slice(0, 8);
  console.log(`${color}[${timestamp}] [${service}]\x1b[0m ${message}`);
}

const COLORS = {
  api: '\x1b[36m',      // Cyan
  frontend: '\x1b[35m', // Magenta
  workers: '\x1b[33m',  // Yellow
  system: '\x1b[32m',   // Green
};

async function startService(
  name: string,
  cmd: string[],
  env: Record<string, string> = {},
  color: string
): Promise<Subprocess> {
  log(name, `Starting: ${cmd.join(' ')}`, color);

  const proc = spawn({
    cmd,
    cwd: ROOT,
    env: { ...process.env, ...env },
    stdout: 'pipe',
    stderr: 'pipe',
  });

  // Stream stdout
  (async () => {
    const reader = proc.stdout.getReader();
    const decoder = new TextDecoder();
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      const lines = decoder.decode(value).split('\n').filter(Boolean);
      for (const line of lines) {
        log(name, line, color);
      }
    }
  })();

  // Stream stderr
  (async () => {
    const reader = proc.stderr.getReader();
    const decoder = new TextDecoder();
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      const lines = decoder.decode(value).split('\n').filter(Boolean);
      for (const line of lines) {
        log(name, `[stderr] ${line}`, color);
      }
    }
  })();

  processes.push(proc);
  return proc;
}

async function shutdown(signal: string) {
  if (shuttingDown) return;
  shuttingDown = true;

  log('system', `Received ${signal}, shutting down...`, COLORS.system);

  for (const proc of processes) {
    try {
      proc.kill();
    } catch {
      // Process may have already exited
    }
  }

  // Give processes time to cleanup
  await new Promise((resolve) => setTimeout(resolve, 1000));

  log('system', 'All services stopped', COLORS.system);
  process.exit(0);
}

// Handle shutdown signals
process.on('SIGINT', () => shutdown('SIGINT'));
process.on('SIGTERM', () => shutdown('SIGTERM'));

async function main() {
  console.log('\n');
  log('system', '='.repeat(60), COLORS.system);
  log('system', 'MMS Development Server', COLORS.system);
  log('system', '='.repeat(60), COLORS.system);
  console.log('');

  // Start API Server
  await startService(
    'api',
    ['bun', 'run', 'src/api/server.ts'],
    { PORT: API_PORT },
    COLORS.api
  );

  // Brief delay to let API start
  await new Promise((resolve) => setTimeout(resolve, 500));

  // Start Workers (if requested)
  if (WORKERS) {
    await startService(
      'workers',
      ['bun', 'run', 'src/workers/runner.ts'],
      { WORKERS },
      COLORS.workers
    );
    await new Promise((resolve) => setTimeout(resolve, 500));
  }

  // Start Vite with proxy configured to API
  await startService(
    'frontend',
    ['bunx', 'vite'],
    {
      VITE_PORT,
      VITE_API_URL: `http://localhost:${API_PORT}`,
    },
    COLORS.frontend
  );

  console.log('');
  log('system', '='.repeat(60), COLORS.system);
  log('system', `API Server:  http://localhost:${API_PORT}`, COLORS.system);
  log('system', `Frontend:    http://localhost:${VITE_PORT}`, COLORS.system);
  if (WORKERS) {
    log('system', `Workers:     ${WORKERS === 'all' ? 'ALL' : WORKERS}`, COLORS.system);
  }
  log('system', '='.repeat(60), COLORS.system);
  log('system', 'Press Ctrl+C to stop all services', COLORS.system);
  console.log('');

  // Keep process alive
  await new Promise(() => {});
}

main().catch((error) => {
  console.error('Failed to start development server:', error);
  process.exit(1);
});

import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

/**
 * MMS Frontend Vite Configuration
 *
 * Dynamic Port Support:
 * - VITE_PORT=0 or unset: Random available port (default for dev)
 * - VITE_PORT=<number>: Use specific port (fallback to next available if busy)
 *
 * The actual assigned port is output in the Vite console.
 * Look for "Local: http://localhost:<port>" to get the actual port.
 */

// Default to port 0 (random) for development
const port = process.env.VITE_PORT !== undefined ? parseInt(process.env.VITE_PORT) : 0

// Backend API URL for proxy (defaults to localhost:3000 for development)
// Set VITE_API_URL environment variable to override
const apiUrl = process.env.VITE_API_URL || 'http://localhost:3000'

export default defineConfig({
  plugins: [react()],
  server: {
    port,
    strictPort: false,
    host: true,
    proxy: {
      '/api': {
        target: apiUrl,
        changeOrigin: true,
        secure: false,
      },
    },
  },
})

/**
 * MMS API Server Entry Point
 *
 * Starts the Hono server using Bun runtime with dynamic port allocation.
 * Use this file to start the API server standalone.
 *
 * Usage: bun run src/api/server.ts
 *
 * Environment Variables:
 * - PORT: Server port (default: 0 = random available port)
 * - HOST: Server host (default: 0.0.0.0)
 * - NODE_ENV: Environment (development, production, test)
 *
 * Dynamic Port Support:
 * - PORT=0 assigns a random available port (recommended for dev/testing)
 * - The actual assigned port is logged and written to stdout for parsing
 * - Look for "API_SERVER_PORT=<port>" in output to get the actual port
 */

import { getApp } from './index';
import { logger } from '../lib/logging/logger';

const PORT = process.env.PORT !== undefined ? Number(process.env.PORT) : 0;
const HOST = process.env.HOST || '0.0.0.0';

const app = getApp();

const server = Bun.serve({
  port: PORT,
  hostname: HOST,
  fetch: app.fetch,
});

// Output actual assigned port (useful for scripts and test harnesses)
const actualPort = server.port;
console.log(`API_SERVER_PORT=${actualPort}`);

logger.info(
  { port: actualPort, host: HOST, env: process.env.NODE_ENV },
  `MMS API server listening on http://${HOST}:${actualPort}`
);

export { server, actualPort };

