     1→/**
     2→ * MMS REST API
     3→ *
     4→ * Main Hono application setup with middleware and route registration.
     5→ * Provides RESTful endpoints for the Metro Fleet Mileage Management System.
     6→ *
     7→ * Base URL: /api/v1
     8→ * Authentication: Bearer JWT
     9→ * Rate Limiting: 100 requests/minute per user (Redis sliding window)
    10→ *
    11→ * @see specs/005-api.md
    12→ */
    13→
    14→import { Hono } from 'hono';
    15→import { cors } from 'hono/cors';
    16→import { logger as honoLogger } from 'hono/logger';
    17→import { secureHeaders } from 'hono/secure-headers';
    18→import { timing } from 'hono/timing';
    19→import {
    20→  requestContext,
    21→  createErrorHandler,
    22→  notFoundHandler,
    23→  tracingMiddleware,
    24→  rateLimiter,
    25→  strictRateLimiter,
    26→} from './middleware';
    27→import { authRoutes, fleetRoutes, pmScheduleRoutes, mileageRoutes, optimizerRoutes, baselineRoutes, driftRoutes, manhourRoutes, canvasRoutes, costingRoutes, materialRoutes, scenarioRoutes, exportRoutes, integrationRoutes, baselineAssumptionRoutes } from './routes';
    28→import { success, type AppVariables } from './types';
    29→import { logger } from '../lib/logging/logger';
    30→import { createOpenApiRoutes } from './openapi';
    31→import { getMetrics, getMetricsContentType } from '../lib/metrics';
    32→import { checkDatabaseHealth } from '../lib/db/connection';
    33→import { checkRedisHealth } from '../lib/redis/connection';
    34→
    35→/**
    36→ * Create the main Hono application
    37→ */
    38→export function createApp(): Hono<{ Variables: AppVariables }> {
    39→  const app = new Hono<{ Variables: AppVariables }>();
    40→
    41→  // ==========================================================================
    42→  // Global Middleware
    43→  // ==========================================================================
    44→
    45→  // Security headers
    46→  app.use('*', secureHeaders());
    47→
    48→  // CORS configuration
    49→  app.use(
    50→    '*',
    51→    cors({
    52→      origin: (origin) => {
    53→        // Allow localhost for development
    54→        if (!origin) return '';
    55→        if (origin.includes('localhost') || origin.includes('127.0.0.1')) {
    56→          return origin;
    57→        }
    58→        // Add production origins here
    59→        return '';
    60→      },
    61→      allowMethods: ['GET', 'POST', 'PATCH', 'PUT', 'DELETE', 'OPTIONS'],
    62→      allowHeaders: ['Content-Type', 'Authorization', 'X-Request-ID'],
    63→      exposeHeaders: ['X-Request-ID', 'X-Response-Time'],
    64→      maxAge: 3600,
    65→      credentials: true,
    66→    })
    67→  );
    68→
    69→  // Request ID and timing
    70→  app.use('*', requestContext());
    71→
    72→  // Server timing headers
    73→  app.use('*', timing());
    74→
    75→  // Request logging (development)
    76→  if (process.env.NODE_ENV !== 'production') {
    77→    app.use('*', honoLogger());
    78→  }
    79→
    80→  // OpenTelemetry tracing
    81→  app.use('*', tracingMiddleware());
    82→
    83→  // Rate limiting (100 requests/minute per user, spec 005)
    84→  // Applied after auth middleware so we can use user ID for rate limiting
    85→  app.use('/api/*', rateLimiter({
    86→    // Skip rate limiting for health endpoints and docs
    87→    skip: (c) => {
    88→      const path = c.req.path;
    89→      return path === '/api/v1' || path === '/api/v1/docs';
    90→    },
    91→  }));
    92→
    93→  // Stricter rate limiting for auth endpoints (10 requests/minute)
    94→  app.use('/api/v1/auth/*', strictRateLimiter());
    95→
    96→  // ==========================================================================
    97→  // Health Endpoints (outside /api/v1)
    98→  // ==========================================================================
    99→
   100→  /**
   101→   * GET /health
   102→   *
   103→   * Liveness probe - returns 200 if process is running.
   104→   */
   105→  app.get('/health', (c) => {
   106→    return c.json({ status: 'healthy', timestamp: new Date().toISOString() });
   107→  });
   108→
   109→  /**
   110→   * GET /ready
   111→   *
   112→   * Readiness probe - returns 200 if service is ready to accept traffic.
   113→   * Checks database and Redis connections with timeout.
   114→   *
   115→   * @returns 200 if all services healthy, 503 if any service unhealthy
   116→   */
   117→  app.get('/ready', async (c) => {
   118→    const HEALTH_CHECK_TIMEOUT = 5000; // 5 seconds
   119→
   120→    // Helper to add timeout to health check
   121→    const withTimeout = async (
   122→      promise: Promise<boolean>,
   123→      timeoutMs: number,
   124→      name: string
   125→    ): Promise<{ healthy: boolean; error?: string }> => {
   126→      try {
   127→        const result = await Promise.race([
   128→          promise.then((ok) => ({ ok, timeout: false as const })),
   129→          new Promise<{ ok: boolean; timeout: true }>((resolve) =>
   130→            setTimeout(() => resolve({ ok: false, timeout: true }), timeoutMs)
   131→          ),
   132→        ]);
   133→        if (result.timeout) {
   134→          return { healthy: false, error: `${name} health check timeout` };
   135→        }
   136→        return { healthy: result.ok };
   137→      } catch (err) {
   138→        return { healthy: false, error: err instanceof Error ? err.message : 'Unknown error' };
   139→      }
   140→    };
   141→
   142→    // Run health checks in parallel with timeout
   143→    const [dbHealth, redisHealth] = await Promise.all([
   144→      withTimeout(checkDatabaseHealth(), HEALTH_CHECK_TIMEOUT, 'Database'),
   145→      withTimeout(checkRedisHealth(), HEALTH_CHECK_TIMEOUT, 'Redis'),
   146→    ]);
   147→
   148→    const checks = {
   149→      database: dbHealth.healthy ? 'healthy' : 'unhealthy',
   150→      databaseError: dbHealth.error,
   151→      redis: redisHealth.healthy ? 'healthy' : 'unhealthy',
   152→      redisError: redisHealth.error,
   153→      timestamp: new Date().toISOString(),
   154→    };
   155→
   156→    const allHealthy = dbHealth.healthy && redisHealth.healthy;
   157→
   158→    // Return 503 Service Unavailable if any check fails
   159→    if (!allHealthy) {
   160→      return c.json({ status: 'not_ready', checks }, 503);
   161→    }
   162→
   163→    return c.json({ status: 'ready', checks });
   164→  });
   165→
   166→  /**
   167→   * GET /metrics
   168→   *
   169→   * Prometheus metrics endpoint for scraping.
   170→   * Returns metrics in Prometheus text format.
   171→   *
   172→   * @see specs/004-domain-services.md Section 4.14
   173→   */
   174→  app.get('/metrics', async (c) => {
   175→    const metrics = await getMetrics();
   176→    return c.text(metrics, 200, {
   177→      'Content-Type': getMetricsContentType(),
   178→    });
   179→  });
   180→
   181→  // ==========================================================================
   182→  // API v1 Routes
   183→  // ==========================================================================
   184→
   185→  const api = new Hono<{ Variables: AppVariables }>();
   186→
   187→  /**
   188→   * GET /api/v1
   189→   *
   190→   * API information endpoint.
   191→   */
   192→  api.get('/', (c) => {
   193→    return c.json(
   194→      success({
   195→        name: 'MMS API',
   196→        version: '1.0.0',
   197→        description: 'Metro Fleet Mileage Management System API',
   198→        documentation: '/api/v1/docs',
   199→        openapi: '/api/v1/openapi.json',
   200→      })
   201→    );
   202→  });
   203→
   204→  // OpenAPI Documentation Routes
   205→  createOpenApiRoutes(api);
   206→
   207→  // Authentication Routes
   208→  api.route('/', authRoutes);
   209→
   210→  // Fleet Management Routes
   211→  api.route('/', fleetRoutes);
   212→
   213→  // PM Schedule Management Routes
   214→  api.route('/', pmScheduleRoutes);
   215→
   216→  // Mileage Management Routes
   217→  api.route('/', mileageRoutes);
   218→
   219→  // Optimizer Routes
   220→  api.route('/', optimizerRoutes);
   221→
   222→  // Baseline Management Routes
   223→  api.route('/', baselineRoutes);
   224→
   225→  // Drift Analysis Routes
   226→  api.route('/', driftRoutes);
   227→
   228→  // Man-hour Management Routes
   229→  api.route('/', manhourRoutes);
   230→
   231→  // Canvas Data Routes
   232→  api.route('/', canvasRoutes);
   233→
   234→  // Costing Routes
   235→  api.route('/', costingRoutes);
   236→
   237→  // Material Management Routes
   238→  api.route('/', materialRoutes);
   239→
   240→  // Scenario Management Routes
   241→  api.route('/', scenarioRoutes);
   242→
   243→  // Export Routes
   244→  api.route('/', exportRoutes);
   245→
   246→  // Integration Routes (Maximo, webhooks)
   247→  api.route('/', integrationRoutes);
   248→
   249→  // Baseline Assumption Routes (Cold Start / Data Migration)
   250→  api.route('/', baselineAssumptionRoutes);
   251→
   252→  // Mount API at /api/v1
   253→  app.route('/api/v1', api);
   254→
   255→  // ==========================================================================
   256→  // Error Handling
   257→  // ==========================================================================
   258→
   259→  // Not found handler for unmatched routes
   260→  app.notFound(notFoundHandler());
   261→
   262→  // Global error handler
   263→  app.onError(createErrorHandler());
   264→
   265→  return app;
   266→}
   267→
   268→/**
   269→ * Singleton app instance
   270→ */
   271→let appInstance: Hono<{ Variables: AppVariables }> | null = null;
   272→
   273→/**
   274→ * Get the Hono app instance (creates if not exists)
   275→ */
   276→export function getApp(): Hono<{ Variables: AppVariables }> {
   277→  if (!appInstance) {
   278→    appInstance = createApp();
