/**
 * MMS REST API
 *
 * Main Hono application setup with middleware and route registration.
 * Provides RESTful endpoints for the Metro Fleet Mileage Management System.
 *
 * Base URL: /api/v1
 * Authentication: Bearer JWT
 * Rate Limiting: 100 requests/minute per user (Redis sliding window)
 *
 * @see specs/005-api.md
 */

import { Hono } from 'hono';
import { cors } from 'hono/cors';
import { logger as honoLogger } from 'hono/logger';
import { secureHeaders } from 'hono/secure-headers';
import { timing } from 'hono/timing';
import {
  requestContext,
  createErrorHandler,
  notFoundHandler,
  tracingMiddleware,
  rateLimiter,
  strictRateLimiter,
} from './middleware';
import { authRoutes, fleetRoutes, pmScheduleRoutes, mileageRoutes, optimizerRoutes, baselineRoutes, driftRoutes, manhourRoutes, canvasRoutes, costingRoutes, materialRoutes, scenarioRoutes, exportRoutes, integrationRoutes, baselineAssumptionRoutes } from './routes';
import { success, type AppVariables } from './types';
import { logger } from '../lib/logging/logger';
import { createOpenApiRoutes } from './openapi';
import { getMetrics, getMetricsContentType } from '../lib/metrics';
import { checkDatabaseHealth } from '../lib/db/connection';
import { checkRedisHealth } from '../lib/redis/connection';

/**
 * Create the main Hono application
 */
export function createApp(): Hono<{ Variables: AppVariables }> {
  const app = new Hono<{ Variables: AppVariables }>();

  // ==========================================================================
  // Global Middleware
  // ==========================================================================

  // Security headers
  app.use('*', secureHeaders());

  // CORS configuration
  app.use(
    '*',
    cors({
      origin: (origin) => {
        // Allow localhost for development
        if (!origin) return '';
        if (origin.includes('localhost') || origin.includes('127.0.0.1')) {
          return origin;
        }
        // Add production origins here
        return '';
      },
      allowMethods: ['GET', 'POST', 'PATCH', 'PUT', 'DELETE', 'OPTIONS'],
      allowHeaders: ['Content-Type', 'Authorization', 'X-Request-ID'],
      exposeHeaders: ['X-Request-ID', 'X-Response-Time'],
      maxAge: 3600,
      credentials: true,
    })
  );

  // Request ID and timing
  app.use('*', requestContext());

  // Server timing headers
  app.use('*', timing());

  // Request logging (development)
  if (process.env.NODE_ENV !== 'production') {
    app.use('*', honoLogger());
  }

  // OpenTelemetry tracing
  app.use('*', tracingMiddleware());

  // Rate limiting (100 requests/minute per user, spec 005)
  // Applied after auth middleware so we can use user ID for rate limiting
  app.use('/api/*', rateLimiter({
    // Skip rate limiting for health endpoints and docs
    skip: (c) => {
      const path = c.req.path;
      return path === '/api/v1' || path === '/api/v1/docs';
    },
  }));

  // Stricter rate limiting for auth endpoints (10 requests/minute)
  app.use('/api/v1/auth/*', strictRateLimiter());

  // ==========================================================================
  // Health Endpoints (outside /api/v1)
  // ==========================================================================

  /**
   * GET /health
   *
   * Liveness probe - returns 200 if process is running.
   */
  app.get('/health', (c) => {
    return c.json({ status: 'healthy', timestamp: new Date().toISOString() });
  });

  /**
   * GET /ready
   *
   * Readiness probe - returns 200 if service is ready to accept traffic.
   * Checks database and Redis connections with timeout.
   *
   * @returns 200 if all services healthy, 503 if any service unhealthy
   */
  app.get('/ready', async (c) => {
    const HEALTH_CHECK_TIMEOUT = 5000; // 5 seconds

    // Helper to add timeout to health check
    const withTimeout = async (
      promise: Promise<boolean>,
      timeoutMs: number,
      name: string
    ): Promise<{ healthy: boolean; error?: string }> => {
      try {
        const result = await Promise.race([
          promise.then((ok) => ({ ok, timeout: false as const })),
          new Promise<{ ok: boolean; timeout: true }>((resolve) =>
            setTimeout(() => resolve({ ok: false, timeout: true }), timeoutMs)
          ),
        ]);
        if (result.timeout) {
          return { healthy: false, error: `${name} health check timeout` };
        }
        return { healthy: result.ok };
      } catch (err) {
        return { healthy: false, error: err instanceof Error ? err.message : 'Unknown error' };
      }
    };

    // Run health checks in parallel with timeout
    const [dbHealth, redisHealth] = await Promise.all([
      withTimeout(checkDatabaseHealth(), HEALTH_CHECK_TIMEOUT, 'Database'),
      withTimeout(checkRedisHealth(), HEALTH_CHECK_TIMEOUT, 'Redis'),
    ]);

    const checks = {
      database: dbHealth.healthy ? 'healthy' : 'unhealthy',
      databaseError: dbHealth.error,
      redis: redisHealth.healthy ? 'healthy' : 'unhealthy',
      redisError: redisHealth.error,
      timestamp: new Date().toISOString(),
    };

    const allHealthy = dbHealth.healthy && redisHealth.healthy;

    // Return 503 Service Unavailable if any check fails
    if (!allHealthy) {
      return c.json({ status: 'not_ready', checks }, 503);
    }

    return c.json({ status: 'ready', checks });
  });

  /**
   * GET /metrics
   *
   * Prometheus metrics endpoint for scraping.
   * Returns metrics in Prometheus text format.
   *
   * @see specs/004-domain-services.md Section 4.14
   */
  app.get('/metrics', async (c) => {
    const metrics = await getMetrics();
    return c.text(metrics, 200, {
      'Content-Type': getMetricsContentType(),
    });
  });

  // ==========================================================================
  // API v1 Routes
  // ==========================================================================

  const api = new Hono<{ Variables: AppVariables }>();

  /**
   * GET /api/v1
   *
   * API information endpoint.
   */
  api.get('/', (c) => {
    return c.json(
      success({
        name: 'MMS API',
        version: '1.0.0',
        description: 'Metro Fleet Mileage Management System API',
        documentation: '/api/v1/docs',
        openapi: '/api/v1/openapi.json',
      })
    );
  });

  // OpenAPI Documentation Routes
  createOpenApiRoutes(api);

  // Authentication Routes
  api.route('/', authRoutes);

  // Fleet Management Routes
  api.route('/', fleetRoutes);

  // PM Schedule Management Routes
  api.route('/', pmScheduleRoutes);

  // Mileage Management Routes
  api.route('/', mileageRoutes);

  // Optimizer Routes
  api.route('/', optimizerRoutes);

  // Baseline Management Routes
  api.route('/', baselineRoutes);

  // Drift Analysis Routes
  api.route('/', driftRoutes);

  // Man-hour Management Routes
  api.route('/', manhourRoutes);

  // Canvas Data Routes
  api.route('/', canvasRoutes);

  // Costing Routes
  api.route('/', costingRoutes);

  // Material Management Routes
  api.route('/', materialRoutes);

  // Scenario Management Routes
  api.route('/', scenarioRoutes);

  // Export Routes
  api.route('/', exportRoutes);

  // Integration Routes (Maximo, webhooks)
  api.route('/', integrationRoutes);

  // Baseline Assumption Routes (Cold Start / Data Migration)
  api.route('/', baselineAssumptionRoutes);

  // Mount API at /api/v1
  app.route('/api/v1', api);

  // ==========================================================================
  // Error Handling
  // ==========================================================================

  // Not found handler for unmatched routes
  app.notFound(notFoundHandler());

  // Global error handler
  app.onError(createErrorHandler());

  return app;
}

/**
 * Singleton app instance
 */
let appInstance: Hono<{ Variables: AppVariables }> | null = null;

/**
 * Get the Hono app instance (creates if not exists)
 */
export function getApp(): Hono<{ Variables: AppVariables }> {
  if (!appInstance) {
    appInstance = createApp();
    logger.info('MMS API initialized');
  }
  return appInstance;
}

/**
 * Export types for external use
 */
export type {
  SuccessResponse,
  ErrorResponse,
  PaginationMeta,
  AppVariables,
  AuthUser,
} from './types';
export { success, paginatedSuccess, error, ErrorCodes } from './types';

