/**
 * MMS Application Root
 *
 * Main application component that assembles the layout and provides
 * state management context via @belt/tools machine.
 *
 * @see specs/006-user-interface.md Section 6.2 Application Layout
 */

import { Classes, OverlaysProvider } from '@blueprintjs/core';

import { Header, Toolbar, Sidebar, StatusBar, InfiniteCanvas, ManHourOverlayPanel, DriftOverlayPanel, ScenarioComparisonView, ModalContainer, ToastManager, AlertBanner } from './components';
import { useUi, useCanvas, useScenario } from './store';
import type { UiSliceState } from './store/slices/ui';
import type { CanvasSliceState } from './store/slices/canvas';
import type { ScenarioSliceState } from './store/slices/scenario';

import './App.css';

function AppContent() {
  const { state: uiStateRaw } = useUi();
  const { state: canvasStateRaw } = useCanvas();
  const { state: scenarioStateRaw } = useScenario();

  const uiState = uiStateRaw as unknown as UiSliceState;
  const canvasState = canvasStateRaw as unknown as CanvasSliceState;
  const scenarioState = scenarioStateRaw as unknown as ScenarioSliceState;

  // Apply theme class to body
  const themeClass = uiState.theme === 'dark' ? Classes.DARK : '';

  // Determine if any overlay panels should be visible
  const showManhourPanel = canvasState.layers?.manhourOverlay ?? false;
  const showDriftPanel = canvasState.layers?.driftOverlay ?? false;
  const showScenarioComparison = scenarioState.activeScenarioId && scenarioState.comparisonBaselineId;
  const hasRightPanel = showManhourPanel || showDriftPanel || showScenarioComparison;

  return (
    <div className={`mms-app ${themeClass}`} data-testid="mms-app">
      {/* Alert Banner - system-wide notifications */}
      <AlertBanner />

      {/* Fixed Header */}
      <Header />

      {/* Main Container (below header) */}
      <div className="mms-main">
        {/* Toolbar */}
        <Toolbar />

        {/* Content Area */}
        <div className="mms-content">
          {/* Left Sidebar - Train List */}
          <Sidebar />

          {/* Main Canvas Area */}
          <InfiniteCanvas />

          {/* Right Overlay Panels */}
          {hasRightPanel && (
            <div className="mms-overlay-panels" style={{
              width: '360px',
              flexShrink: 0,
              display: 'flex',
              flexDirection: 'column',
              gap: '8px',
              padding: '8px',
              backgroundColor: 'var(--pt-app-background-color, #f5f8fa)',
              borderLeft: '1px solid var(--pt-divider-color, #e1e8ed)',
              overflowY: 'auto',
            }}>
              {showManhourPanel && <ManHourOverlayPanel />}
              {showDriftPanel && <DriftOverlayPanel />}
              {showScenarioComparison && <ScenarioComparisonView />}
            </div>
          )}
        </div>

        {/* Status Bar */}
        <StatusBar />
      </div>

      {/* Modal Container - renders active modals */}
      <ModalContainer />

      {/* Toast Notifications - positioned top-right */}
      <ToastManager />
    </div>
  );
}

function App() {
  return (
    <OverlaysProvider>
      <AppContent />
    </OverlaysProvider>
  );
}

export default App;

