 *
 * Central state management using @belt/tools machines.
 * This replaces React hooks (useState, useEffect) and zustand per project constraints.
 *
 * @see specs/006-user-interface.md Section 6.4
 * @see README.md for @belt/tools API reference
 */

import { createMachine } from '@belt/tools';

import {
  fleetSlice,
  fleetAsyncSlice,
  canvasSlice,
  canvasDataSlice,
  pmSlice,
  pmAsyncSlice,
  scenarioSlice,
  scenarioAsyncSlice,
  uiSlice,
  overlaySlice,
} from './slices';

// =============================================================================
// MMS Application Machine
// =============================================================================

/**
 * Main application state machine.
 *
 * Usage in React components:
 * ```tsx
 * function TrainList() {
 *   const { state, actions } = mmsMachine.useMachine('fleet');
 *   return (
 *     <ul>
 *       {state.trains.map(train => (
 *         <li key={train.id} onClick={() => actions.selectTrain(train.id)}>
 *           {train.trainNumber}
 *         </li>
 *       ))}
 *     </ul>
 *   );
 * }
 * ```
 */
export const mmsMachine = createMachine({
  id: 'mms',
  slices: {
    fleet: fleetSlice,
    fleetApi: fleetAsyncSlice,
    canvas: canvasSlice,
    canvasData: canvasDataSlice,
    pm: pmSlice,
    pmApi: pmAsyncSlice,
    scenario: scenarioSlice,
    scenarioApi: scenarioAsyncSlice,
    ui: uiSlice,
    overlay: overlaySlice,
  },
  context: {
    // User ID for private cache policy
    userID: null as string | null,
    // Context properties for async slices
    baseUrl: '/api/v1',
    startDate: new Date().toISOString().split('T')[0],
    endDate: new Date(Date.now() + 84 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
  },
});

// =============================================================================
// Type Exports
// =============================================================================

export type MmsMachine = typeof mmsMachine;
export type MmsSliceId = keyof typeof mmsMachine extends infer K
  ? K extends 'useMachine' | 'useSlice' | 'dispatch' | 'getState' | 'subscribe'
    ? never
    : K
  : never;

// =============================================================================
// Re-exports
// =============================================================================

// Types
export * from './types';

// Slices
export * from './slices';

// Batch utilities
export {
  batchDispatch,
  batchDispatches,
  flushBatch,
  cancelBatch,
  getBatchStatus,
  createBatchedDispatcher,
  debouncedBatchDispatch,
  throttledBatchDispatch,
  createPointerMoveHandler,
  createWheelHandler,
} from './utils/batch';

// =============================================================================
// Convenience Hooks
// =============================================================================

/**
 * Hook for fleet state and actions
 *
 * @example
 * ```tsx
 * function FleetView() {
 *   const { state, actions } = useFleet();
 *   return <div>{state.trains.length} trains</div>;
 * }
 * ```
 */
export function useFleet() {
  return mmsMachine.useMachine('fleet');
}

/**
 * Hook for canvas state and actions
 *
 * @example
 * ```tsx
 * function Canvas() {
 *   const { state, actions } = useCanvas();
 *   return <div>Zoom: {state.zoom}</div>;
 * }
 * ```
 */
export function useCanvas() {
  return mmsMachine.useMachine('canvas');
}

/**
 * Hook for canvas data (strategic/tactical views)
 *
 * @example
 * ```tsx
 * function StrategicView() {
 *   const { state, actions } = useCanvasData();
 *   if (state.strategicLoading) return <Spinner />;
 *   return <Heatmap data={state.strategicData} />;
 * }
 * ```
 */
export function useCanvasData() {
  return mmsMachine.useMachine('canvasData');
}

/**
 * Hook for PM schedule state and actions
 *
 * @example
 * ```tsx
 * function PmSchedule() {
 *   const { state, actions } = usePm();
 *   return <div>{state.pmSchedule.length} PMs</div>;
 * }
 * ```
 */
export function usePm() {
  return mmsMachine.useMachine('pm');
}

/**
 * Hook for scenario state and actions
 *
 * @example
 * ```tsx
 * function ScenarioPanel() {
 *   const { state, actions } = useScenario();
 *   return <div>{state.scenarios.length} scenarios</div>;
 * }
 * ```
 */
export function useScenario() {
  return mmsMachine.useMachine('scenario');
}

/**
 * Hook for UI state and actions
 *
 * @example
 * ```tsx
 * function ToastContainer() {
 *   const { state, actions } = useUi();
 *   return (
 *     <div>
 *       {state.toasts.map(toast => (
 *         <Toast key={toast.id} {...toast} onDismiss={() => actions.removeToast(toast.id)} />
 *       ))}
 *     </div>
 *   );
 * }
 * ```
 */
export function useUi() {
  return mmsMachine.useMachine('ui');
}

/**
 * Hook for overlay state and actions (manhour, drift)
 *
 * @example
 * ```tsx
 * function OverlayPanel() {
 *   const { state, actions } = useOverlay();
 *   return (
 *     <div>
 *       {state.manhourData && <ManHourChart data={state.manhourData} />}
 *       {state.driftData && <DriftList data={state.driftData} />}
 *     </div>
 *   );
 * }
 * ```
 */
export function useOverlay() {
  return mmsMachine.useMachine('overlay');
}

// =============================================================================
// Async Data Hooks
// =============================================================================

/**
 * Hook for async fleet data loading
 *
 * @example
 * ```tsx
 * function FleetLoader() {
 *   const { data, loading, error, refetch } = useFleetApi();
 *
 *   if (loading) return <Spinner />;
 *   if (error) return <Error message={error.message} />;
 *
 *   return <FleetView data={data} />;
 * }
 * ```
 */
export function useFleetApi() {
  return mmsMachine.useMachine('fleetApi');
}

/**
 * Hook for async PM data loading
 */
export function usePmApi() {
  return mmsMachine.useMachine('pmApi');
}

/**
 * Hook for async scenario data loading
 */
export function useScenarioApi() {
  return mmsMachine.useMachine('scenarioApi');
}

