/**
 * Fleet Management Routes
 *
 * REST endpoints for fleet, train, depot, and route management.
 * Wraps FleetService with HTTP interface per spec 005.3.
 *
 * @see specs/005-api.md Section 5.3
 */

import { Hono } from 'hono';
import {
  success,
  paginatedSuccess,
  error,
  parsePaginationQuery,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import { getFleetService, type TrainListFilters, type FleetListFilters } from '../../services';
import { isValidUuid } from '../../lib/schemas';

// Singleton service instance
let fleetService: ReturnType<typeof getFleetService> | null = null;

function getService(): ReturnType<typeof getFleetService> {
  if (!fleetService) {
    fleetService = getFleetService();
  }
  return fleetService;
}

export const fleetRoutes = new Hono<{ Variables: AppVariables }>();

/**
 * GET /fleets
 *
 * List all fleet types with train counts.
 */
fleetRoutes.get('/fleets', async (c) => {
  const service = getService();

  // Parse query filters
  const filters: FleetListFilters = {};
  const baseDepotId = c.req.query('baseDepotId');
  const manufacturer = c.req.query('manufacturer');
  const active = c.req.query('active');

  if (baseDepotId && isValidUuid(baseDepotId)) {
    filters.baseDepotId = baseDepotId;
  }
  if (manufacturer) {
    filters.manufacturer = manufacturer;
  }
  if (active !== undefined) {
    filters.active = active === 'true';
  }

  const fleets = await service.listFleets(filters);

  // Enrich with train counts using fleet statistics
  const enrichedFleets = await Promise.all(
    fleets.map(async (fleet) => {
      try {
        const stats = await service.getFleetStatistics(fleet.id);
        return {
          id: fleet.id,
          code: fleet.code,
          name: fleet.name,
          manufacturer: fleet.manufacturer,
          model: fleet.model,
          carsPerTrain: fleet.carsPerTrain,
          trainCount: stats.totalTrains,
          activeTrainCount: stats.activeTrains,
        };
      } catch {
        // If statistics fail, return basic fleet data
        return {
          id: fleet.id,
          code: fleet.code,
          name: fleet.name,
          manufacturer: fleet.manufacturer,
          model: fleet.model,
          carsPerTrain: fleet.carsPerTrain,
          trainCount: 0,
          activeTrainCount: 0,
        };
      }
    })
  );

  return c.json(
    success(enrichedFleets, {
      timing: { durationMs: getRequestDuration(c) },
    })
  );
});

/**
 * GET /fleets/:id
 *
 * Get fleet details by ID.
 */
fleetRoutes.get('/fleets/:id', async (c) => {
  const requestId = getRequestId(c);
  const fleetId = c.req.param('id');

  if (!isValidUuid(fleetId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid fleet ID format', requestId), 400);
  }

  const service = getService();
  const fleet = await service.getFleetById(fleetId);
  const stats = await service.getFleetStatistics(fleetId);

  return c.json(
    success({
      id: fleet.id,
      code: fleet.code,
      name: fleet.name,
      manufacturer: fleet.manufacturer,
      model: fleet.model,
      carsPerTrain: fleet.carsPerTrain,
      trainCount: stats.totalTrains,
      activeTrainCount: stats.activeTrains,
      fitTrains: stats.fitTrains,
      restrictedTrains: stats.restrictedTrains,
      groundedTrains: stats.groundedTrains,
      statistics: {
        totalMileageKm: stats.totalMileageKm,
        averageMileageKm: stats.averageMileageKm,
        minMileageKm: stats.minMileageKm,
        maxMileageKm: stats.maxMileageKm,
      },
    })
  );
});

/**
 * GET /trains
 *
 * List trains with filtering and pagination.
 */
fleetRoutes.get('/trains', async (c) => {
  const service = getService();

  // Parse query filters
  const filters: TrainListFilters = {};
  const fleetId = c.req.query('fleetId');
  const depotId = c.req.query('depotId');
  const fitnessStatus = c.req.query('fitnessStatus');
  const active = c.req.query('active');

  if (fleetId && isValidUuid(fleetId)) {
    filters.fleetId = fleetId;
  }
  if (depotId && isValidUuid(depotId)) {
    filters.depotId = depotId;
  }
  if (fitnessStatus) {
    const validStatuses = ['FIT', 'RESTRICTED', 'GROUNDED'] as const;
    if (validStatuses.includes(fitnessStatus as (typeof validStatuses)[number])) {
      filters.fitnessStatus = fitnessStatus as 'FIT' | 'RESTRICTED' | 'GROUNDED';
    }
  }
  if (active !== undefined) {
    filters.active = active === 'true';
  }

  // Parse pagination
  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
    sort: c.req.query('sort'),
  });

  const result = await service.listTrains(filters, {
    page: pagination.page,
    pageSize: pagination.pageSize,
    sortBy: pagination.sort?.field,
    sortOrder: pagination.sort?.direction,
  });

  // Map to API response format
  // Calculate mileage variance as current - target
  const trains = result.data.map((train) => ({
    id: train.id,
    trainNumber: train.trainNumber,
    fleetId: train.fleetId,
    currentMileageKm: train.currentMileageKm,
    targetMileageKm: train.targetMileageKm,
    mileageVarianceKm: train.targetMileageKm
      ? train.currentMileageKm - train.targetMileageKm
      : null,
    fitnessStatus: train.fitnessStatus,
    currentDepotId: train.currentDepotId,
    homeDepotId: train.homeDepotId,
    commissioningDate: train.commissioningDate,
    isActive: train.active,
  }));

  return c.json(
    paginatedSuccess(
      trains,
      {
        page: result.page,
        pageSize: result.pageSize,
        totalItems: result.total,
      },
      { durationMs: getRequestDuration(c) }
    )
  );
});

/**
 * GET /trains/:id
 *
 * Get detailed train information.
 */
fleetRoutes.get('/trains/:id', async (c) => {
  const requestId = getRequestId(c);
  const trainId = c.req.param('id');

  if (!isValidUuid(trainId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid train ID format', requestId), 400);
  }

  const service = getService();
  const trainWithDetails = await service.getTrainWithDetails(trainId);

  // Calculate mileage variance
  const mileageVarianceKm = trainWithDetails.targetMileageKm
    ? trainWithDetails.currentMileageKm - trainWithDetails.targetMileageKm
    : null;

  return c.json(
    success({
      id: trainWithDetails.id,
      trainNumber: trainWithDetails.trainNumber,
      fleet: trainWithDetails.fleet
        ? {
            id: trainWithDetails.fleet.id,
            code: trainWithDetails.fleet.code,
            name: trainWithDetails.fleet.name,
          }
        : null,
      currentMileageKm: trainWithDetails.currentMileageKm,
      targetMileageKm: trainWithDetails.targetMileageKm,
      mileageVarianceKm,
      fitnessStatus: trainWithDetails.fitnessStatus,
      fitnessNotes: trainWithDetails.fitnessNotes,
      currentDepot: trainWithDetails.currentDepot
        ? {
            id: trainWithDetails.currentDepot.id,
            code: trainWithDetails.currentDepot.code,
            name: trainWithDetails.currentDepot.name,
          }
        : null,
      homeDepot: trainWithDetails.homeDepot
        ? {
            id: trainWithDetails.homeDepot.id,
            code: trainWithDetails.homeDepot.code,
            name: trainWithDetails.homeDepot.name,
          }
        : null,
      commissioningDate: trainWithDetails.commissioningDate,
      isActive: trainWithDetails.active,
    })
  );
});

/**
 * PATCH /trains/:id
 *
 * Update train properties (fitness status, notes).
 */
fleetRoutes.patch('/trains/:id', async (c) => {
  const requestId = getRequestId(c);
  const trainId = c.req.param('id');

  if (!isValidUuid(trainId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid train ID format', requestId), 400);
  }

  const body = await c.req.json();
  const service = getService();

  // Handle fitness status change
  if (body.fitnessStatus) {
    const validStatuses = ['FIT', 'RESTRICTED', 'GROUNDED'];
    if (!validStatuses.includes(body.fitnessStatus)) {
      return c.json(
        error(
          ErrorCodes.VALIDATION_ERROR,
          `Invalid fitness status. Must be one of: ${validStatuses.join(', ')}`,
          requestId
        ),
        400
      );
    }

    await service.updateFitnessStatus({
      trainId,
      newStatus: body.fitnessStatus,
      notes: body.fitnessNotes,
      changedBy: c.get('user')?.id,
    });
  }

  // Get updated train
  const updatedTrain = await service.getTrainById(trainId);

  return c.json(
    success({
      id: updatedTrain.id,
      fitnessStatus: updatedTrain.fitnessStatus,
      fitnessNotes: updatedTrain.fitnessNotes,
      updatedAt: updatedTrain.updatedAt,
    })
  );
});

/**
